def validate_tools(tools: Sequence[Tool]) -> None:
        """Validate tool collection according to smolagents constraints."""
        # Reject non-sequence, strings, bytes
        if not isinstance(tools, collections.abc.Sequence):
            raise ValueError("tools must be a Sequence")
        if isinstance(tools, (str, bytes)):
            raise ValueError("tools cannot be a string or bytes")
        # Empty sequence
        if len(tools) == 0:
            raise ValueError("tools cannot be empty")
        # Check each tool
        seen_names = set()
        for i, tool in enumerate(tools):
            if not isinstance(tool, Tool):
                raise ValueError(f"Tool at index {i} is not a smolagents Tool")
            if not callable(tool):
                raise ValueError(f"Tool at index {i} is not callable")
            name = getattr(tool, 'name', None)
            if not name or not isinstance(name, str):
                raise ValueError(f"Tool at index {i} lacks a valid name attribute")
            lower_name = name.lower()
            if lower_name in seen_names:
                raise ValueError(f"Duplicate tool name (case-insensitive): '{name}'")
            seen_names.add(lower_name)
        # All checks passed
        return None
